    if (!a || !b || !c) return -1;
    memset(c, 0, sizeof(*c));
    FILE *in = fopen(a, "rb");
    if (!in) {
        c->reason = REASON_MISSING;
        snprintf(c->msg, sizeof(c->msg), "open failed");
        return -2;
    }
