            folded.cells[gi] = st->grid.cells[start];
            folded.cells[gi].idx = gi;
            folded.cells[gi].tier = 0;
            folded.cells[gi].parent = -1;
            continue;
        }
        CellPatch children;
        children.n = k;
        for (int j = 0; j < k && j < MAX_LEAVES; j++) {
            children.vol[j] = st->grid.cells[start + j].vol;
            for (int v = 0; v < NVAR; v++) {
